import './App.css';
import axios from 'axios';
// import {BrowserRouter as Router, Routes, Route} from 'react-router-dom'
// import Login from './pages/Login'
// import Home from './pages/Home'
// import Road from './pages/Road'
// import Sing from './pages/Sing'
// import RoadSing from './pages/Road_Sing'

const api = axios.create({
  baseURL: 'http://localhost:5000',
  withCredentials: true,
});


function App() {
 const [login, setlogin] = useState('');
  const [password, setPassword] = useState('');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [userData, setUserData] = useState(null);
  const [protectedData, setProtectedData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // // Проверяем авторизацию при загрузке
  // useEffect(() => {
  //   checkAuth();
  // }, []);

  // const checkAuth = async () => {
  //   try {
  //     const response = await api.get('/api/check-auth');
  //     if (response.data.authenticated) {
  //       setIsLoggedIn(true);
  //       setUserData({ login: response.data.login });
  //     }
  //   } catch (err) {
  //     console.log('Not authenticated');
  //   }
  // };

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const response = await api.post('/login', {
        login,
        password,
      });

      if (response.data.success) {
        setIsLoggedIn(true);
        setUserData({ login: response.data.login });
        setlogin('');
        setPassword('');
      }
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    try {
      await api.post('/logout');
      setIsLoggedIn(false);
      setUserData(null);
      setProtectedData(null);
    } catch (err) {
      console.error('Logout error:', err);
    }
  };

  // const fetchProtectedData = async () => {
  //   try {
  //     const response = await api.get('/api/protected-data');
  //     setProtectedData(response.data);
  //   } catch (err) {
  //     if (err.response?.status === 401) {
  //       setIsLoggedIn(false);
  //       setError('Session expired. Please login again.');
  //     } else {
  //       setError('Failed to fetch data');
  //     }
  //   }
  // };

  if (isLoggedIn) {
    return (
      <div style={styles.container}>
        <div style={styles.card}>
          <h2 style={styles.title}>Welcome, {userData?.login}!</h2>
          <p style={styles.subtitle}>You are logged in successfully.</p>

          <div style={styles.buttonGroup}>
            <button 
              onClick={fetchProtectedData}
              style={styles.button}
            >
              Get Protected Data
            </button>

            <button 
              onClick={handleLogout}
              style={{...styles.button, ...styles.logoutButton}}
            >
              Logout
            </button>
          </div>

          {protectedData && (
            <div style={styles.dataCard}>
              <h3>Protected Data:</h3>
              <p><strong>Message:</strong> {protectedData.data}</p>
              <p><strong>Time:</strong> {protectedData.timestamp}</p>
            </div>
          )}

          {error && (
            <div style={styles.error}>{error}</div>
          )}
        </div>
      </div>
    );
  }

  return (
    // <Router>
    //   <Routes>
    //     <Route path="/" element={<Home />} />
    //     <Route path="/login" element={<Login />} />

    //     <Route path="/roads" element={<Road />} />
    //     <Route path="/sings" element={<Sing />} />
    //     <Route path="/roads/sings" element={<RoadSing />} />

    //   </Routes>
    // </Router>
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>Login</h2>

        {error && (
          <div style={styles.error}>{error}</div>
        )}

        <form onSubmit={handleLogin} style={styles.form}>
          <div style={styles.inputGroup}>
            <label style={styles.label}>login</label>
            <input
              type="text"
              value={login}
              onChange={(e) => setlogin(e.target.value)}
              style={styles.input}
              placeholder="admin or user"
              required
            />
          </div>

          <div style={styles.inputGroup}>
            <label style={styles.label}>Password</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              style={styles.input}
              placeholder="admin123 or user123"
              required
            />
          </div>

          <button 
            type="submit" 
            disabled={loading}
            style={styles.button}
          >
            {loading ? 'Logging in...' : 'Login'}
          </button>
        </form>

        <div style={styles.credentials}>
          <p><strong>Test credentials:</strong></p>
          <p>login: admin, Password: admin123</p>
          <p>login: user, Password: user123</p>
        </div>
      </div>
    </div>
  );
}
  // Простые стили
  const styles = {
    container: {
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      minHeight: '100vh',
      backgroundColor: '#f5f5f5',
      padding: '20px',
    },
    card: {
      backgroundColor: 'white',
      borderRadius: '10px',
      padding: '40px',
      boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)',
      width: '100%',
      maxWidth: '400px',
    },
    title: {
      textAlign: 'center',
      marginBottom: '10px',
      color: '#333',
    },
    subtitle: {
      textAlign: 'center',
      color: '#666',
      marginBottom: '30px',
    },
    form: {
      display: 'flex',
      flexDirection: 'column',
      gap: '20px',
    },
    inputGroup: {
      display: 'flex',
      flexDirection: 'column',
      gap: '5px',
    },
    label: {
      fontWeight: 'bold',
      color: '#555',
    },
    input: {
      padding: '10px',
      border: '1px solid #ddd',
      borderRadius: '5px',
      fontSize: '16px',
    },
    button: {
      backgroundColor: '#007bff',
      color: 'white',
      padding: '12px',
      border: 'none',
      borderRadius: '5px',
      fontSize: '16px',
      cursor: 'pointer',
      fontWeight: 'bold',
      marginTop: '10px',
    },
    logoutButton: {
      backgroundColor: '#dc3545',
    },
    buttonGroup: {
      display: 'flex',
      gap: '10px',
      marginBottom: '20px',
    },
    dataCard: {
      backgroundColor: '#e8f5e9',
      padding: '15px',
      borderRadius: '5px',
      marginTop: '20px',
    },
    error: {
      backgroundColor: '#ffebee',
      color: '#c62828',
      padding: '10px',
      borderRadius: '5px',
      marginBottom: '20px',
      textAlign: 'center',
    },
    credentials: {
      marginTop: '20px',
      padding: '15px',
      backgroundColor: '#f8f9fa',
      borderRadius: '5px',
      fontSize: '14px',
      color: '#666',
    }
}

export default App;
